#!/usr/bin/env node

/**
 * Reformat Toff Descriptions (only those previously generated by this software)
 *
 * For each product whose Neo4j `descriptionSource` indicates the description was
 * generated by THIS software (not manually by the TOFF team), this script takes
 * the EXISTING description from Neo4j and asks Gemini to REWRITE it following
 * the new TOFF rules — without doing Google Search or image vision (much faster
 * and cheaper than full regeneration). Factual details are preserved; only
 * style/wording/banned-words are corrected.
 *
 * Manual descriptions (descriptionSource = "original") are NEVER touched.
 *
 * Sources considered "ours" (will be reformatted):
 *   - google_search_grounding-1 (and any other google_search_*)
 *   - ai_image
 *   - ai_image_grounding_429
 *   - ai_rewrite
 *   - ai_reformat (re-run on already-reformatted ones)
 *
 * Sources NEVER touched:
 *   - original          (manually set by TOFF team)
 *   - none, none_grounding_429, error
 *   - null
 *
 * Usage:
 *   node apps/api/src/scripts/regen-toff-descriptions.js [--dry-run] [--limit N] [--handle <handle-or-url>] [--no-push] [--concurrency N]
 *
 * Options:
 *   --dry-run                 Generate descriptions but do NOT save to Neo4j or push to VTEX
 *   --limit <N>               Process at most N products (useful for staged rollout)
 *   --handle <handle-or-url>  Process a single product by handle or toff.ro URL
 *   --no-push                 Save to Neo4j but do NOT push to VTEX (useful for staged review)
 *   --concurrency <N>         Parallel workers (default: 5). Higher = faster but watch Gemini quota.
 *
 * Examples:
 *   node apps/api/src/scripts/regen-toff-descriptions.js --dry-run --limit 5
 *   node apps/api/src/scripts/regen-toff-descriptions.js --limit 10 --concurrency 5
 *   node apps/api/src/scripts/regen-toff-descriptions.js --handle acne-studios-rochie-camasa-cu-esarfa-aplicata-a20937-dlc
 *   node apps/api/src/scripts/regen-toff-descriptions.js --concurrency 10           # all ~1932 ours, faster
 */

import dotenv from "dotenv";
import { fileURLToPath } from "url";
import path from "path";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
dotenv.config({ path: path.resolve(__dirname, "../../../../.env") });

import neo4j from "neo4j-driver";
import fetch from "node-fetch";
import { NEO4J_URI, NEO4J_USER, NEO4J_PASSWORD } from "../sync/services/config.js";
import { reformatDescriptionWithToffRules } from "../sync/services/ai-product-description.js";
import { mapWithConcurrency } from "../sync/utils/index.js";

// ─── Toff defaults ───────────────────────────────────────────────────

const accountName = process.env.VTEX_ACCOUNT || "toffro";
const appKey = process.env.VTEX_API_KEY;
const appToken = process.env.VTEX_API_TOKEN;

// ─── CLI args ────────────────────────────────────────────────────────

const args = process.argv.slice(2);
const dryRun = args.includes("--dry-run");
const noPush = args.includes("--no-push");
const limitIdx = args.indexOf("--limit");
const limit = limitIdx !== -1 ? parseInt(args[limitIdx + 1], 10) : null;
const concurrencyIdx = args.indexOf("--concurrency");
const concurrency = concurrencyIdx !== -1 ? Math.max(1, parseInt(args[concurrencyIdx + 1], 10) || 1) : 5;
const handleIdx = args.indexOf("--handle");
let singleHandle = handleIdx !== -1 ? args[handleIdx + 1] : null;
if (singleHandle) {
  const urlMatch = singleHandle.match(/toff\.ro\/([^/]+)\/p/);
  if (urlMatch) singleHandle = urlMatch[1];
}

const STORE_ID = `${accountName}.vtexcommercestable.com.br`;
const BASE_URL = `https://${accountName}.vtexcommercestable.com.br`;
const HEADERS = {
  "Content-Type": "application/json",
  Accept: "application/json",
  "X-VTEX-API-AppKey": appKey,
  "X-VTEX-API-AppToken": appToken,
};

const MAX_RETRIES = 5;

// Sources that mean "previously generated by this software" → eligible for reformat
const OUR_SOURCES_CYPHER = `(
  p.descriptionSource STARTS WITH 'google_search_'
  OR p.descriptionSource STARTS WITH 'ai_image'
  OR p.descriptionSource = 'ai_rewrite'
  OR p.descriptionSource = 'ai_reformat'
)`;

// ─── Neo4j ───────────────────────────────────────────────────────────

function getDriver() {
  return neo4j.driver(NEO4J_URI, neo4j.auth.basic(NEO4J_USER, NEO4J_PASSWORD));
}

async function getOurProducts({ limit, handle }) {
  const driver = getDriver();
  const session = driver.session();
  try {
    if (handle) {
      const r = await session.run(
        `MATCH (p:Product)
         WHERE p.storeId = $storeId AND p.handle = $handle
         RETURN p.id AS id, p.title AS title, p.handle AS handle, p.sku AS sku,
                p.vendor AS vendor, p.image AS image, p.images AS images,
                p.descriptionSource AS descriptionSource, p.description AS description`,
        { storeId: STORE_ID, handle }
      );
      return r.records.map(rec => mapRecord(rec));
    }

    const limitClause = limit ? `LIMIT ${limit}` : "";
    const r = await session.run(
      `MATCH (p:Product)
       WHERE p.storeId = $storeId
         AND p.descriptionSource IS NOT NULL
         AND ${OUR_SOURCES_CYPHER}
       RETURN p.id AS id, p.title AS title, p.handle AS handle, p.sku AS sku,
              p.vendor AS vendor, p.image AS image, p.images AS images,
              p.descriptionSource AS descriptionSource, p.description AS description
       ORDER BY p.title
       ${limitClause}`,
      { storeId: STORE_ID }
    );
    return r.records.map(rec => mapRecord(rec));
  } finally {
    await session.close();
    await driver.close();
  }
}

function mapRecord(rec) {
  return {
    id: rec.get("id"),
    title: rec.get("title"),
    handle: rec.get("handle"),
    sku: rec.get("sku"),
    vendor: rec.get("vendor"),
    image: rec.get("image"),
    images: rec.get("images"),
    descriptionSource: rec.get("descriptionSource"),
    description: rec.get("description"),
  };
}

async function saveDescriptionToNeo4j(driver, productId, description, source) {
  const session = driver.session();
  try {
    await session.run(
      `MATCH (p:Product {id: $id, storeId: $storeId})
       SET p.description = $description,
           p.descriptionSource = $source,
           p.updated_at = $now`,
      {
        id: String(productId),
        storeId: STORE_ID,
        description,
        source,
        now: new Date().toISOString(),
      }
    );
  } finally {
    await session.close();
  }
}

// ─── VTEX API ────────────────────────────────────────────────────────

function delay(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function vtexRequest(endpoint, options = {}) {
  const url = `${BASE_URL}${endpoint}`;
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      const res = await fetch(url, {
        method: options.method || "GET",
        headers: HEADERS,
        body: options.body ? JSON.stringify(options.body) : undefined,
      });
      if (res.status === 429) {
        const retryAfter = parseInt(res.headers.get("retry-after") || "0", 10);
        const backoff = retryAfter > 0 ? retryAfter * 1000 : Math.min(2000 * Math.pow(2, attempt), 60000);
        if (attempt < MAX_RETRIES) {
          console.log(`  [VTEX] 429 rate-limited, waiting ${(backoff / 1000).toFixed(1)}s (retry ${attempt + 1}/${MAX_RETRIES})...`);
          await delay(backoff);
          continue;
        }
      }
      if (!res.ok) {
        const text = await res.text();
        throw new Error(`${res.status} - ${text}`);
      }
      return res.json();
    } catch (error) {
      if ((error.code === "ECONNRESET" || error.code === "ETIMEDOUT") && attempt < MAX_RETRIES) {
        const backoff = Math.min(2000 * Math.pow(2, attempt), 30000);
        console.log(`  [VTEX] ${error.code}, retrying in ${(backoff / 1000).toFixed(1)}s...`);
        await delay(backoff);
        continue;
      }
      throw error;
    }
  }
}

async function getVtexProduct(productId) {
  return vtexRequest(`/api/catalog/pvt/product/${productId}`);
}

async function updateVtexDescription(productId, vtexProduct, newDescription) {
  return vtexRequest(`/api/catalog/pvt/product/${productId}`, {
    method: "PUT",
    body: { ...vtexProduct, Description: newDescription },
  });
}

// ─── Main ────────────────────────────────────────────────────────────

async function main() {
  console.log(`\n═══════════════════════════════════════════════════════════`);
  console.log(`  Regen Toff Descriptions (only previously AI-generated ones)`);
  console.log(`  Store:        ${STORE_ID}`);
  console.log(`  Mode:         ${dryRun ? "DRY RUN (no writes)" : "LIVE"}`);
  console.log(`  Push to VTEX: ${dryRun ? "no (dry-run)" : (noPush ? "no (--no-push)" : "yes")}`);
  console.log(`  Concurrency:  ${concurrency} worker(s)`);
  if (limit) console.log(`  Limit:        ${limit} products`);
  if (singleHandle) console.log(`  Handle:       ${singleHandle}`);
  console.log(`═══════════════════════════════════════════════════════════\n`);

  console.log(`[1] Fetching products from Neo4j (only those with our generated descriptions)...`);
  const products = await getOurProducts({ limit, handle: singleHandle });
  console.log(`    Found ${products.length} products to regenerate\n`);

  if (products.length === 0) {
    console.log("Nothing to do.");
    return;
  }

  if (singleHandle && products[0].descriptionSource === "original") {
    console.log(`    Product handle "${singleHandle}" has descriptionSource = "original" (manually set).`);
    console.log(`    SKIPPING — this script never touches manual descriptions.`);
    return;
  }

  const sharedDriver = getDriver();
  const stats = { checked: 0, regenerated: 0, savedNeo4j: 0, pushedVtex: 0, skipped: 0, errors: 0, gemFailed: 0 };
  const startedAt = Date.now();

  try {
    await mapWithConcurrency(products, concurrency, async (p, i, total) => {
      stats.checked++;
      const tag = `[${String(stats.checked).padStart(String(total).length)}/${total}]`;

      try {
        if (!p.description || p.description.trim().length < 30) {
          console.log(`${tag} ✗ "${p.title}" — no existing description (too short), skipping`);
          stats.skipped++;
          return;
        }

        console.log(`${tag} ⏳ "${p.title}" (id: ${p.id}, source: ${p.descriptionSource})`);

        const aiResult = await reformatDescriptionWithToffRules(
          {
            title: p.title,
            vendor: p.vendor,
            currentDescription: p.description,
          },
          { language: "ro" }
        );

        if (!aiResult || !aiResult.text) {
          console.log(`${tag} ✗ "${p.title}" — Gemini returned no description`);
          stats.gemFailed++;
          return;
        }

        stats.regenerated++;

        if (dryRun) {
          console.log(`${tag} ✓ "${p.title}" — reformatted (${p.description.length}→${aiResult.text.length}ch) [DRY RUN, not saved]`);
          return;
        }

        await saveDescriptionToNeo4j(sharedDriver, p.id, aiResult.text, aiResult.source);
        stats.savedNeo4j++;

        if (noPush) {
          console.log(`${tag} ✓ "${p.title}" — reformatted (${aiResult.text.length}ch), saved to Neo4j, VTEX push skipped (--no-push)`);
          return;
        }

        const vtexProduct = await getVtexProduct(p.id);
        await updateVtexDescription(p.id, vtexProduct, aiResult.text);
        stats.pushedVtex++;
        console.log(`${tag} ✓ "${p.title}" — reformatted (${aiResult.text.length}ch), saved + pushed to VTEX`);
      } catch (err) {
        if (err.message && err.message.includes("404")) {
          console.log(`${tag} ✗ "${p.title}" (id ${p.id}) — not found in VTEX`);
        } else {
          console.error(`${tag} ✗ "${p.title}" — ERROR: ${err.message}`);
        }
        stats.errors++;
      }
    });
  } finally {
    await sharedDriver.close();
  }

  const elapsed = ((Date.now() - startedAt) / 1000).toFixed(1);
  const avgPerProduct = products.length > 0 ? (parseFloat(elapsed) / products.length).toFixed(1) : "0";

  console.log(`\n═══════════════════════════════════════════════════════════`);
  console.log(`  RESULTS${dryRun ? " (DRY RUN)" : ""}`);
  console.log(`    Checked:                ${stats.checked}`);
  console.log(`    Regenerated by Gemini:  ${stats.regenerated}`);
  console.log(`    Saved to Neo4j:         ${stats.savedNeo4j}`);
  console.log(`    Pushed to VTEX:         ${stats.pushedVtex}`);
  console.log(`    Skipped:                ${stats.skipped}`);
  console.log(`    Gemini failures:        ${stats.gemFailed}`);
  console.log(`    Errors:                 ${stats.errors}`);
  console.log(`    Elapsed:                ${elapsed}s (${avgPerProduct}s/product avg, concurrency ${concurrency})`);
  console.log(`═══════════════════════════════════════════════════════════\n`);
}

main()
  .then(() => process.exit(0))
  .catch(e => {
    console.error("\nFatal error:", e);
    process.exit(1);
  });
